/** Get the logo URL for a provider from the models.dev repo. */
export function getProviderLogoUrl(providerId: string): string | null {
  const provider = MODELS_DEV_PROVIDERS.find(p => p.id === providerId);
  if (!provider || !provider.icon?.startsWith("logo:")) return null;
  return `https://raw.githubusercontent.com/anomalyco/models.dev/dev/providers/${providerId}/logo.svg`;
}